[
  "handler:start",
  {
    "uid": "pickForm",
    "eventName": "submit",
    "componentType": "Form",
    "componentLabel": "pickForm",
    "args": [
      {
        "title": "Stewart's Point Coastal Route",
        "date": "2026-03-08",
        "time": "08:20",
        "endTime": "11:20",
        "location": "Mate Rio Community Centre, Bohemian Highway and Highway 116",
        "description": "Coastal route event at Stewart's Point."
      },
      {
        "passAsDefaultBody": true
      }
    ],
    "ownerFileId": "http://localhost:8080/components/PickEditor.xmlui",
    "ownerSource": {
      "start": 3677,
      "end": 11267
    },
    "handlerCode": "(data) => {
        if (!window.authUser?.id) {
          errorMessage = 'Please sign in to pick events';
          return;
        }
        errorMessage = '';
        const formData = pickForm.getData();
        if ($props.event?.id) {
          createPickApi.execute({
            user_id: window.authUser.id,
            event_id: $props.event.id
          });
          if (rruleFrequency !== 'none') {
            const rruleStr = window.buildRRule(rruleFrequency, rruleDays, rruleOrdinal, rruleMonthDay);
            const startTime = (formData.date || '') + 'T' + (formData.time || '00:00') + ':00';
            const endTime = formData.endTime ? (formData.date || '') + 'T' + formData.endTime + ':00' : null;
            enrichmentApi.execute({
              event_id: $props.event.id,
              curator_id: window.authUser.id,
              rrule: rruleStr,
              title: formData.title,
              start_time: startTime,
              end_time: endTime,
              location: formData.location || null,
              description: formData.description || null,
              city: window.cityFilter || null,
              curator_name: window.authUser.user_metadata?.user_name || window.authUser.email || 'curator'
            });
          }
        } else {
          const startTime = (formData.date || '') + 'T' + (formData.time || '00:00') + ':00';
          const endTime = formData.endTime ? (formData.date || '') + 'T' + formData.endTime + ':00' : null;
          captureApi.execute({
            mode: 'commit',
            event: {
              title: formData.title,
              start_time: startTime,
              end_time: endTime,
              location: formData.location || null,
              description: formData.description || null,
              url: $props.event?.url || null,
              city: window.cityFilter || null
            },
            transcript: $props.event?.transcript || null
          });
        }
        isSaving = true;
      }"
  }
]

